$ErrorActionPreference = "Stop"
$root = Split-Path -Parent (Split-Path -Parent $PSScriptRoot)
$dist = Join-Path $root "dist"
$journalManifestPath = Join-Path $root 'journals\manifest.json'
$journalPartialPath = Join-Path $root 'partials\travel-journal.html'
$journalStarterPath = Join-Path $root 'journals\_template.html'

function Assert-FileSizeBudget([string]$RelativePath, [int]$MaximumKB) {
    $path = Join-Path $dist $RelativePath
    if (-not (Test-Path -LiteralPath $path)) { throw "Performance budget target is missing: $RelativePath" }
    $size = (Get-Item -LiteralPath $path).Length
    if ($size -gt ($MaximumKB * 1KB)) {
        throw "$RelativePath exceeds its $MaximumKB KB performance budget ($([math]::Round($size / 1KB, 1)) KB)."
    }
}

if (-not (Test-Path -LiteralPath $dist)) { throw "Missing dist directory. Run tools/site.ps1 build first." }
if (-not (Test-Path -LiteralPath $journalManifestPath) -or -not (Test-Path -LiteralPath $journalPartialPath) -or -not (Test-Path -LiteralPath $journalStarterPath)) { throw "Travel journal manifest, shared partial, or starter is missing." }
$journalManifestData = Get-Content -LiteralPath $journalManifestPath -Raw -Encoding UTF8 | ConvertFrom-Json
$journalManifest = @($journalManifestData | Sort-Object order)
$journalPartial = Get-Content -LiteralPath $journalPartialPath -Raw -Encoding UTF8
$journalStarter = Get-Content -LiteralPath $journalStarterPath -Raw -Encoding UTF8
if ($journalManifest.Count -ne 9 -or ($journalManifest.slug | Select-Object -Unique).Count -ne $journalManifest.Count) { throw "Travel journal manifest must contain nine unique journal slugs." }
foreach ($partialToken in @('{{MAIN_ATTRIBUTES}}', '{{TRIP_NAVIGATION}}', '{{JOURNAL_CONTENT}}', '{{TRIP_PAGINATION}}')) {
    if ($journalPartial -notmatch [regex]::Escape($partialToken)) { throw "Shared travel journal partial is missing token: $partialToken" }
}
if ($journalPartial -notmatch 'data-journal-template="v2"') { throw "Shared travel journal shell must expose its versioned layout contract." }
if ($journalStarter -notmatch 'travel-journal__hero-image guangzhou-journal__hero-image' -or $journalStarter -notmatch 'travel-journal__route guangzhou-day__route guangzhou-day__route--collapsible' -or $journalStarter -notmatch 'travel-gallery travel-gallery--compact masonry mason4' -or $journalStarter -notmatch 'travel-gallery__item--tall[^\"]*guangzhou-gallery__brick--tall' -or $journalStarter -notmatch '--hero-focus-x:' -or $journalStarter -notmatch '--focus-x:') { throw "Travel journal starter must demonstrate the responsive hero, collapsible route, compact gallery, tall collage, and focal-point controls." }
$modularJournals = @($journalManifest | Where-Object { $_.contentOnly })
if ($modularJournals.Count -ne $journalManifest.Count -or $modularJournals.slug -notcontains 'travel_2026_guangzhou') { throw "Every travel journal must use the content-only build path, with Guangzhou retained as the reference implementation." }
foreach ($journal in $modularJournals) {
    if ($journal.source -notmatch '^journals/travel_[^/]+\.html$') { throw "$($journal.slug) must source its content fragment from the journals directory." }
    $journalSourcePath = Join-Path $root ($journal.source -replace '/', '\')
    if (-not (Test-Path -LiteralPath $journalSourcePath)) { throw "Missing journal content fragment: $($journal.source)" }
    $journalSource = Get-Content -LiteralPath $journalSourcePath -Raw -Encoding UTF8
    if ($journalSource -match '<(?:!DOCTYPE|html|head|body)\b|<div id="main"|<footer id="footer"') { throw "$($journal.source) must contain journal content only, without a document shell." }
}
$pages = Get-ChildItem -LiteralPath $dist -Filter *.html -File
if ($pages.Count -ne 17) { throw "Expected 17 generated pages, found $($pages.Count)." }
$retiredPaths = @(
    'league.html',
    'experience_ndu.html',
    'assets\css\slider1.css',
    'assets\css\slider2.css',
    'assets\css\webflow.css',
    'assets\js\animate.js',
    'assets\js\slider1.js',
    'assets\js\slider2.js',
    'assets\js\jquery.min.js',
    'assets\js\jquery.scrollex.min.js',
    'assets\js\jquery.scrolly.min.js',
    'assets\js\browser.min.js',
    'assets\js\breakpoints.min.js',
    'assets\js\util.js',
    'assets\js\arrow.js'
)
foreach ($retiredPath in $retiredPaths) {
    if (Test-Path -LiteralPath (Join-Path $dist $retiredPath)) { throw "Retired page asset was published: $retiredPath" }
}
$eventPageNames = @('house.html', 'prewed.html')
$journalPageNames = @($journalManifest | ForEach-Object { "$($_.slug).html" })
$routeCssOwners = @{
    'travel-map-page.css' = @('travel.html')
    'travel-journal.css' = $journalPageNames
    'experience-page.css' = @('experience.html')
    'personal-page.css' = @('personal.html')
    'skills-page.css' = @('skills.html')
}
$navSignatures = [System.Collections.Generic.HashSet[string]]::new([System.StringComparer]::Ordinal)

foreach ($page in $pages) {
    $html = Get-Content -LiteralPath $page.FullName -Raw -Encoding UTF8
    $scan = [regex]::Replace($html, '<!--.*?-->', '', 'Singleline')
    foreach ($tag in @('html', 'head', 'body')) {
        if ([regex]::Matches($scan, "<$tag\b", 'IgnoreCase').Count -ne 1) { throw "$($page.Name) must contain exactly one <$tag> tag." }
    }
    if ([regex]::Matches($scan, '<main\b', 'IgnoreCase').Count -ne 1) { throw "$($page.Name) must contain exactly one <main> landmark." }
    if ([regex]::Matches($scan, '<h1\b', 'IgnoreCase').Count -ne 1) { throw "$($page.Name) must contain exactly one <h1> heading." }
    if ($scan -notmatch '<meta name="viewport" content="width=device-width, initial-scale=1(?:\.0)?') { throw "$($page.Name) is missing the responsive viewport configuration." }
    if ($scan -notmatch 'assets/css/icons\.css\?v=1' -or $scan -notmatch 'assets/css/main\.css\?v=4' -or $scan -notmatch 'assets/css/custom\.css\?v=181' -or $scan -notmatch 'assets/js/main\.js\?v=20') { throw "$($page.Name) is missing the current shared asset versions." }
    if ($scan -notmatch '<link rel="preload" href="assets/fonts/merriweather-300-latin\.woff2" as="font" type="font/woff2" crossorigin />') { throw "$($page.Name) is missing the body-font preload." }
    if ($scan -match 'assets/js/(?:jquery(?:\.scrollex|\.scrolly)?\.min|browser\.min|breakpoints\.min|util|arrow)\.js') { throw "$($page.Name) still loads a retired shared JavaScript dependency." }
    if ($scan -match 'fontawesome\.com|font-awesome/|font-awesome\.min\.css') { throw "$($page.Name) still loads a remote or retired Font Awesome bundle." }
    if ($scan -notmatch 'href=["'']personal["'']') { throw "$($page.Name) is missing the Personal navigation tab." }
    if ($eventPageNames -notcontains $page.Name -and $page.Name -ne 'index.html' -and $scan -notmatch 'class="logo icon fa-home"') { throw "$($page.Name) is missing the centered home control." }
    if ($page.Name -eq 'index.html' -and $scan -match 'class="logo icon fa-home"|<header id="header">') { throw "Homepage must flow directly from its full-screen opening without a redundant home control." }
    if ($page.Name -ne 'index.html' -and ($scan -match '<canvas id="nokey"|assets/js/canvas-background\.js')) { throw "$($page.Name) must not run the homepage background canvas." }
    if ($page.Name -ne 'index.html' -and $scan -match 'assets/js/game\.js') { throw "$($page.Name) must not load the homepage interaction bundle." }
    if ($page.Name -in @('skills.html', 'travel.html')) {
        if ($scan -notmatch 'assets/js/listing-effects\.js\?v=2') { throw "$($page.Name) is missing its listing effects bundle." }
    } elseif ($scan -match 'assets/js/listing-effects\.js') { throw "$($page.Name) must not load the listing effects bundle." }
    if ($journalPageNames -contains $page.Name) {
        if ($scan -notmatch 'assets/js/journal-progress\.js\?v=1') { throw "$($page.Name) is missing its reading-progress bundle." }
        # The banner is the LCP element; a responsive head preload must start its
        # download during head parsing rather than waiting for the body <img>.
        $bannerImg = [regex]::Match($scan, '<img\b[^>]*\bclass="[^"]*\bjournal-banner\b[^"]*"[^>]*>')
        if (-not $bannerImg.Success) { throw "$($page.Name) is missing its journal banner image." }
        $bannerSrc = [regex]::Match($bannerImg.Value, '\ssrc="([^"]+)"').Groups[1].Value
        $bannerPreload = [regex]::Match($scan, '<link\b[^>]*\brel="preload"[^>]*\bas="image"[^>]*>')
        if (-not $bannerPreload.Success) { throw "$($page.Name) is missing its LCP banner preload." }
        if ($bannerPreload.Value -notmatch 'fetchpriority="high"') { throw "$($page.Name) banner preload must set fetchpriority high." }
        if ($bannerPreload.Value -notmatch [regex]::Escape('href="' + $bannerSrc + '"')) { throw "$($page.Name) banner preload must target the banner image." }
        $headEnd = $scan.IndexOf('</head>')
        if ($headEnd -lt 0 -or $scan.IndexOf($bannerPreload.Value) -gt $headEnd) { throw "$($page.Name) banner preload must live in the document head." }
    } elseif ($scan -match 'assets/js/journal-progress\.js') { throw "$($page.Name) must not load the journal progress bundle." }
    if ($journalPageNames -notcontains $page.Name -and [regex]::IsMatch($scan, '<link\b[^>]*\brel="preload"[^>]*\bas="image"')) { throw "$($page.Name) must not preload a banner image it does not render." }
    foreach ($routeCss in $routeCssOwners.Keys) {
        $hasRouteCss = $scan -match [regex]::Escape("assets/css/$routeCss")
        $expectsRouteCss = $routeCssOwners[$routeCss] -contains $page.Name
        if ($expectsRouteCss -and -not $hasRouteCss) { throw "$($page.Name) is missing its $routeCss stylesheet." }
        if (-not $expectsRouteCss -and $hasRouteCss) { throw "$($page.Name) must not load the $routeCss stylesheet." }
    }
    if ($eventPageNames -contains $page.Name -and $scan -match '<header id="header">') { throw "$($page.Name) still contains the retired event-page banner." }
    if ($scan -match 'class="row rowpad"|\bworkbutton\b') { throw "$($page.Name) still contains retired or inconsistent bottom navigation." }
    $primaryNav = [regex]::Match($scan, '(?s)<nav id="nav">.*?<ul class="links">(.*?)</ul>', 'IgnoreCase')
    if (-not $primaryNav.Success) { throw "$($page.Name) is missing the primary navigation list." }
    $navLabels = foreach ($navLink in [regex]::Matches($primaryNav.Groups[1].Value, '(?s)<a\b[^>]*>(.*?)</a>', 'IgnoreCase')) {
        [System.Net.WebUtility]::HtmlDecode(([regex]::Replace($navLink.Groups[1].Value, '<[^>]+>', '') -replace '\s+', ' ').Trim())
    }
    if (($navLabels -join '|') -ne 'About|Work|Skills|Personal|Travel') { throw "$($page.Name) has inconsistent primary navigation labels." }
    $sharedNav = [regex]::Match($scan, '(?s)<nav id="nav">.*?</nav>', 'IgnoreCase')
    if (-not $sharedNav.Success) { throw "$($page.Name) is missing the shared navigation block." }
    $navSignature = (($sharedNav.Value -replace ' class="active"', '') -replace '\s+', ' ').Trim()
    [void]$navSignatures.Add($navSignature)
    if ([regex]::IsMatch($scan, '<img\b(?=[^>]*\balt="")[^>]*>', 'IgnoreCase')) { throw "$($page.Name) contains an image with empty alt text." }
    if ([regex]::IsMatch($scan, '<a\b(?=[^>]*\bhref="#!")[^>]*>', 'IgnoreCase')) { throw "$($page.Name) contains a dead #! link." }
    $nonTopDeadLink = [regex]::Matches($scan, '<a\b(?=[^>]*\bhref="#")[^>]*>', 'IgnoreCase') | Where-Object { $_.Value -notmatch '\bid="return-to-top"' }
    if ($nonTopDeadLink.Count -gt 0) { throw "$($page.Name) contains a dead # link." }

    $references = [System.Collections.Generic.List[string]]::new()
    foreach ($match in [regex]::Matches($scan, '(?:src|href|data)="([^"#?]+)"', 'IgnoreCase')) {
        $references.Add($match.Groups[1].Value)
    }
    foreach ($match in [regex]::Matches($scan, 'srcset="([^"]+)"', 'IgnoreCase')) {
        foreach ($candidate in $match.Groups[1].Value -split ',') {
            $candidatePath = ($candidate.Trim() -split '\s+')[0]
            if ($candidatePath) { $references.Add($candidatePath) }
        }
    }
    foreach ($reference in $references) {
        if ($reference -match '^(https?:|//|mailto:|javascript:)') { continue }
        $target = Join-Path $dist ($reference -replace '/', '\')
        if (-not (Test-Path -LiteralPath $target) -and [IO.Path]::GetExtension($reference) -eq '') {
            $target = "$target.html"
        }
        if (-not (Test-Path -LiteralPath $target)) { throw "$($page.Name) references missing file: $reference" }
    }
    $scriptBytes = 0
    foreach ($scriptMatch in [regex]::Matches($scan, '<script\b[^>]*\bsrc="(assets/js/[^"?]+)')) {
        $scriptPath = Join-Path $dist ($scriptMatch.Groups[1].Value -replace '/', '\')
        $scriptBytes += (Get-Item -LiteralPath $scriptPath).Length
    }
    if ($scriptBytes -gt 80KB) { throw "$($page.Name) exceeds the 80 KB raw JavaScript budget." }
    if ($page.Length -gt 225KB) { throw "$($page.Name) exceeds the 225 KB generated-HTML budget." }
}

if ($navSignatures.Count -ne 1) { throw "Generated pages do not share one consistent navigation block." }

$travel = Get-Content -LiteralPath (Join-Path $dist 'travel.html') -Raw -Encoding UTF8
$homeHtml = Get-Content -LiteralPath (Join-Path $dist 'index.html') -Raw -Encoding UTF8
$experience = Get-Content -LiteralPath (Join-Path $dist 'experience.html') -Raw -Encoding UTF8
$personal = Get-Content -LiteralPath (Join-Path $dist 'personal.html') -Raw -Encoding UTF8
$house = Get-Content -LiteralPath (Join-Path $dist 'house.html') -Raw -Encoding UTF8
$prewed = Get-Content -LiteralPath (Join-Path $dist 'prewed.html') -Raw -Encoding UTF8
$sharedCustomCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\custom.css') -Raw -Encoding UTF8
$travelMapPageCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\travel-map-page.css') -Raw -Encoding UTF8
$travelJournalCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\travel-journal.css') -Raw -Encoding UTF8
$experiencePageCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\experience-page.css') -Raw -Encoding UTF8
$personalPageCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\personal-page.css') -Raw -Encoding UTF8
$skillsPageCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\skills-page.css') -Raw -Encoding UTF8
$iconsCss = Get-Content -LiteralPath (Join-Path $dist 'assets\css\icons.css') -Raw -Encoding UTF8
$customCss = @($sharedCustomCss, $travelMapPageCss, $travelJournalCss, $experiencePageCss, $personalPageCss, $skillsPageCss) -join "`n"
$personalTimelineJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\personal-timeline.js') -Raw -Encoding UTF8
$galleryJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\gallery.js') -Raw -Encoding UTF8
$travelNavJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\travel-nav.js') -Raw -Encoding UTF8
$travelMapJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\travel-map.js') -Raw -Encoding UTF8
$mainJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\main.js') -Raw -Encoding UTF8
$canvasJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\canvas-background.js') -Raw -Encoding UTF8
$gameJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\game.js') -Raw -Encoding UTF8
$listingEffectsJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\listing-effects.js') -Raw -Encoding UTF8
$journalProgressJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\journal-progress.js') -Raw -Encoding UTF8
$scrambleRevealJs = Get-Content -LiteralPath (Join-Path $dist 'assets\js\scramble-reveal.js') -Raw -Encoding UTF8
Assert-FileSizeBudget 'assets\css\custom.css' 90
Assert-FileSizeBudget 'assets\css\travel-map-page.css' 34
Assert-FileSizeBudget 'assets\css\travel-journal.css' 30
Assert-FileSizeBudget 'assets\css\experience-page.css' 12
Assert-FileSizeBudget 'assets\css\personal-page.css' 32
Assert-FileSizeBudget 'assets\css\skills-page.css' 10
Assert-FileSizeBudget 'assets\css\icons.css' 4
if ($iconsCss -match '@font-face|fontawesome-webfont' -or [regex]::Matches($iconsCss, '\.\bfa-[a-z0-9-]+::before').Count -ne 22) { throw 'The minimal icon stylesheet must map exactly the selected self-hosted page icons without a webfont.' }
$publishedIconSvgs = @(Get-ChildItem -LiteralPath (Join-Path $dist 'assets\icons\fontawesome') -Filter '*.svg' -File -Recurse)
if ($publishedIconSvgs.Count -ne 26 -or ($publishedIconSvgs | Measure-Object Length -Sum).Sum -gt 24KB) { throw 'The self-hosted Font Awesome SVG subset is missing icons or exceeds its 24 KB budget.' }
if (Get-ChildItem -LiteralPath (Join-Path $dist 'assets\fonts') -Filter 'fontawesome*' -File) { throw 'The retired Font Awesome webfont is still published.' }
# The Merriweather files are static single-weight instances of the upstream
# variable font; a regression back to the ~95KB variable files doubles the
# body-font payload on every page.
foreach ($merriweatherCut in @('merriweather-300-latin', 'merriweather-700-latin', 'merriweather-300-italic-latin', 'merriweather-700-italic-latin', 'merriweather-300-latin-ext', 'merriweather-700-latin-ext', 'merriweather-300-italic-latin-ext', 'merriweather-700-italic-latin-ext')) {
    Assert-FileSizeBudget "assets\fonts\$merriweatherCut.woff2" 48
}
if ($sharedCustomCss -match 'Route bundle:|Travel destination atlas|Guangzhou journal|Travel journal navigation\.|Japan editorial title|Quiet Skills-card treatment') { throw 'Generated shared custom.css still contains a route-owned block.' }
if ($travelMapPageCss -notmatch 'Travel destination atlas' -or $travelMapPageCss -notmatch 'Compact travel journal archive') { throw 'Travel index CSS bundle is missing its atlas or archive block.' }
if ($travelJournalCss -notmatch 'Guangzhou journal' -or $travelJournalCss -notmatch 'Travel journal navigation\.' -or $travelJournalCss -notmatch 'Japan editorial title') { throw 'Travel journal CSS bundle is missing a journal-owned block.' }
if ($experiencePageCss -notmatch 'Route bundle: experience-base:start' -or $personalPageCss -notmatch 'Route bundle: personal-responsive:start' -or $skillsPageCss -notmatch 'Quiet Skills-card treatment') { throw 'A page-specific CSS bundle is missing its ownership marker.' }
Assert-FileSizeBudget 'assets\js\main.js' 18
Assert-FileSizeBudget 'assets\js\canvas-background.js' 14
Assert-FileSizeBudget 'assets\js\game.js' 22
Assert-FileSizeBudget 'assets\js\listing-effects.js' 8
Assert-FileSizeBudget 'assets\js\journal-progress.js' 4
if ($listingEffectsJs -notmatch 'prefers-reduced-motion: reduce' -or $listingEffectsJs -notmatch '\.education-grid \.education-card' -or $listingEffectsJs -notmatch '\.travel-grid \.travel-card' -or $listingEffectsJs -notmatch "classList\.add\('js-tilt'\)") { throw 'Listing effects must preserve reduced-motion reveals and pointer tilt for skills and travel cards.' }
if ($listingEffectsJs -notmatch 'REVEAL_DURATION = 480' -or $listingEffectsJs -notmatch 'REVEAL_STAGGER = 60' -or $listingEffectsJs -notmatch "removeProperty\('--reveal-delay'\)" -or $listingEffectsJs -notmatch "classList\.add\('is-reveal-settled'\)") { throw 'Listing reveals must use the compact 480ms motion with a temporary 60ms stagger, then restore immediate hover feedback.' }
if ($mainJs -match '\bjQuery\b|\$\(|\bbreakpoints\s*\(|\.scrollex\b|\bbrowser\.' -or $mainJs -notmatch "window\.matchMedia\('\(max-width: 980px\)'\)" -or $mainJs -notmatch 'new MutationObserver\(syncNavPanelState\)' -or $mainJs -notmatch "navPanelToggle\.addEventListener\('click'" -or $mainJs -notmatch "event\.key === 'Escape'" -or $mainJs -notmatch "returnToTop\.classList\.toggle\('is-visible'" -or $mainJs -notmatch "window\.scrollTo\(\{ top: 0") { throw 'Shared interactions must remain dependency-free while preserving responsive navigation, modal focus, and return-to-top behavior.' }
if ($customCss -notmatch '--motion-fast:\s*150ms' -or $customCss -notmatch '--motion-standard:\s*220ms' -or $customCss -notmatch '--motion-slow:\s*320ms' -or $customCss -notmatch '--motion-reveal:\s*480ms' -or $customCss -notmatch '--motion-spatial:\s*520ms') { throw 'Shared motion duration tokens are missing from custom.css.' }
if ($customCss -match 'transition:\s*all\b') { throw 'Custom CSS must name transition properties instead of animating all properties.' }
if ($customCss -notmatch '(?s)\[data-reveal\]\s*\{[^}]*var\(--motion-reveal\)' -or $customCss -notmatch '(?s)\.travel-section-nav\s*\{[^}]*var\(--motion-standard\)') { throw 'Listing reveals and journal navigation must use the shared motion system.' }
if ($customCss -notmatch '(?s)@media \(prefers-reduced-motion: reduce\)\s*\{[^}]*\.travel-grid \.travel-card[^}]*transition:\s*none' -or $customCss -notmatch '(?s)@media \(prefers-reduced-motion: reduce\)\s*\{[^}]*\.travel-section-nav[^}]*transition:\s*none') { throw 'Shared card and journal navigation motion must provide reduced-motion fallbacks.' }
if ($journalProgressJs -notmatch "bar\.className = 'read-progress'" -or $journalProgressJs -notmatch 'requestAnimationFrame\(update\)' -or $journalProgressJs -notmatch "addEventListener\('resize'") { throw 'Journal progress must remain frame-throttled and respond to layout changes.' }
if ([regex]::Matches($travel, 'class="travel-card"').Count -ne 9) { throw "Travel page must contain nine travel cards." }
if ($travel -notmatch 'class="travel-atlas"' -or $travel -notmatch 'Explore by destination' -or $travel -notmatch 'browse trip stories and photos') { throw "Travel destination atlas or visitor-facing introduction is missing." }
if ([regex]::Matches($travel, 'class="travel-map__marker travel-map__marker--').Count -ne 11) { throw "Travel atlas must contain eleven regional map pins." }
if ([regex]::Matches($travel, 'class="travel-map__marker-label"').Count -ne 11) { throw "Travel atlas must contain eleven thumbnail popovers." }
if ([regex]::Matches($travel, 'class="travel-map__place"').Count -ne 11) { throw "Travel atlas must contain eleven persistent, non-overlapping place labels." }
if ($travel -notmatch 'class="travel-map-teaser" data-map-open' -or $travel -notmatch 'class="travel-map__close" data-map-close' -or [regex]::Matches($travel, 'data-map-region="').Count -ne 4 -or $travel -match 'travel-mobile-destination') { throw "Travel must provide the mobile map teaser, close control, and four region jump chips instead of the retired accordion." }
foreach ($travelDate in @('18 &ndash; 26 December 2017', 'August 2019 &ndash; April 2020','22 October &ndash; 1 November 2022', '28 June &ndash; 8 July 2023', '10 &ndash; 28 October 2023', '2 &ndash; 14 August 2024', '6 &ndash; 28 April 2024', '23 October &ndash; 8 November 2025', '10 &ndash; 15 May 2026')) {
    if ($travel -notmatch [regex]::Escape($travelDate)) { throw "Travel map hover cards are missing trip date: $travelDate" }
}
if ([regex]::Matches($travel, 'class="travel-map__city-links"').Count -ne 11 -or $travel -notmatch 'travel_2017_seoul#trip-section-1' -or $travel -notmatch 'travel_2017_seoul#trip-section-2' -or $travel -notmatch 'travel_2017_seoul#trip-section-3' -or $travel -notmatch 'travel_2023_usacanada#trip-section-2' -or $travel -notmatch 'travel_2023_usacanada#trip-section-6' -or $travel -notmatch 'travel_2023_usacanada#trip-section-9' -or $travel -notmatch 'travel_2023_usacanada#trip-section-11' -or $travel -notmatch 'travel_2023_usacanada#trip-section-14' -or $travel -notmatch 'travel_2024_australia#trip-section-1' -or $travel -notmatch 'travel_2024_australia#trip-section-6') { throw "Travel map pins must target the first matching Seoul, USA, Canada, Melbourne, and Sydney journal sections." }
foreach ($cityLink in [regex]::Matches($travel, 'href="(travel_[^"#]+)#(trip-section-\d+)"')) {
    $targetPage = Join-Path $dist ($cityLink.Groups[1].Value + '.html')
    if (-not (Test-Path -LiteralPath $targetPage)) { throw "Travel map city link points to a missing journal: $($cityLink.Value)" }
    $targetHtml = Get-Content -LiteralPath $targetPage -Raw -Encoding UTF8
    if ($targetHtml -notmatch ('id="' + [regex]::Escape($cityLink.Groups[2].Value) + '"')) { throw "Travel map city link points to a missing section: $($cityLink.Value)" }
}
if ($travel -match 'travel-atlas__destinations|travel-atlas__journal|travel-atlas__thumb') { throw "Travel atlas must not duplicate the journal archive with a destination list." }
if ($travel -match 'Photography &amp; stories|Trips, stories, and photography from 2019 to today') { throw "Travel page must not repeat a separate introductory banner above the destination atlas." }
if ($travel -notmatch '<div class="travel-archive-heading">' -or $travel -notmatch 'All travel journals') { throw "Compact travel journal archive heading is missing or uses inherited header styling." }
foreach ($archiveImage in @('2025_japan/day14_hakone/fuji1.jpg', '2024_australia/melbourne_12apostles/apostles3.jpg', '2024_germany/cologne/cologne-card.jpg', '2023_usa_canada/day2/empire_state1.jpg', '2023_perth/day1/bathers_bay_02.jpg', '2022_europe/day2/paris3-card.jpg')) {
    if ($travel -notmatch [regex]::Escape("images/travel/$archiveImage")) { throw "Travel archive is missing in-journal thumbnail: $archiveImage" }
}
